function nextPermutationBruteForce(numbers: number[]): number[] {
  function generatePermutations(currentNumbers: number[]): number[][] {
    if (currentNumbers.length === 0) {
      return [[]];
    }

    const firstElement = currentNumbers[0];
    const remainingElements = currentNumbers.slice(1);
    const permutationsOfRemainingElements = generatePermutations(remainingElements);

    const allPermutations: number[][] = [];
    for (const permutation of permutationsOfRemainingElements) {
      for (let index = 0; index <= permutation.length; index++) {
        const newPermutation = [...permutation.slice(0, index), firstElement, ...permutation.slice(index)];
        allPermutations.push(newPermutation);
      }
    }
    return allPermutations;
  }

  const allPossiblePermutations = generatePermutations(numbers);
  let nextGreaterPermutation: number[] | null = null;

  // We need to find a permutation greater than the input
  for (const permutation of allPossiblePermutations) {
    let isGreater = false;
    for (let index = 0; index < numbers.length; index++) {
      if (permutation[index] > numbers[index]) {
        isGreater = true;
        break;
      } else if (permutation[index] < numbers[index]) {
        break;
      }
    }

    if (isGreater) {
      // Prioritize the smallest greater candidate
      if (!nextGreaterPermutation) {
        nextGreaterPermutation = permutation;
      } else {
        let isSmaller = false;
        for (let index = 0; index < numbers.length; index++) {
          if (permutation[index] < nextGreaterPermutation[index]) {
            isSmaller = true;
            break;
          } else if (permutation[index] > nextGreaterPermutation[index]) {
            break;
          }
        }
        if (isSmaller) {
          nextGreaterPermutation = permutation;
        }
      }
    }
  }

  // If we couldn't find anything larger, sort.
  if (!nextGreaterPermutation) {
    return numbers.sort((firstNumber, secondNumber) => firstNumber - secondNumber);
  } else {
    return nextGreaterPermutation;
  }
}

