public class NextPermutationBruteForce {

    public static void nextPermutation(int[] numbers) {
        // Generate all possible permutations.
        java.util.List<java.util.List<Integer>> allPermutations = generatePermutations(numbers);

        java.util.List<Integer> originalList = new java.util.ArrayList<>();
        for (int number : numbers) {
            originalList.add(number);
        }

        java.util.List<Integer> nextPermutation = null;
        boolean foundBigger = false;

        for (java.util.List<Integer> permutation : allPermutations) {
            // Find the smallest permutation larger than the original.
            if (isBigger(permutation, originalList)) {
                if (!foundBigger) {
                    nextPermutation = permutation;
                    foundBigger = true;
                } else {
                    if (isBigger(nextPermutation, permutation)) {
                        nextPermutation = permutation;
                    }
                }
            }
        }

        // If no larger permutation found, reverse the array.
        if (!foundBigger) {
            java.util.Arrays.sort(numbers);
        } else {
            for (int i = 0; i < numbers.length; i++) {
                numbers[i] = nextPermutation.get(i);
            }
        }
    }

    private static java.util.List<java.util.List<Integer>> generatePermutations(int[] numbers) {
        java.util.List<java.util.List<Integer>> permutationsList = new java.util.ArrayList<>();
        java.util.List<Integer> currentPermutation = new java.util.ArrayList<>();
        boolean[] used = new boolean[numbers.length];
        generatePermutationsHelper(numbers, used, currentPermutation, permutationsList);
        return permutationsList;
    }

    private static void generatePermutationsHelper(int[] numbers, boolean[] used, java.util.List<Integer> currentPermutation, java.util.List<java.util.List<Integer>> permutationsList) {
        if (currentPermutation.size() == numbers.length) {
            permutationsList.add(new java.util.ArrayList<>(currentPermutation));
            return;
        }

        for (int i = 0; i < numbers.length; i++) {
            if (!used[i]) {
                used[i] = true;
                currentPermutation.add(numbers[i]);
                generatePermutationsHelper(numbers, used, currentPermutation, permutationsList);
                currentPermutation.remove(currentPermutation.size() - 1);
                used[i] = false;
            }
        }
    }

    private static boolean isBigger(java.util.List<Integer> first, java.util.List<Integer> second) {
        for (int i = 0; i < first.size(); i++) {
            if (first.get(i) > second.get(i)) {
                return true;
            } else if (first.get(i).intValue() != second.get(i).intValue()) {
                return false;
            }
        }
        return false;
    }

