package main

import "sort"

func nextPermutationBruteForce(numbers []int) {
	possiblePermutations := generatePermutations(numbers)

	var smallestCandidate []int
	foundNext := false

	for _, permutation := range possiblePermutations {
		// Checking if the permutation is larger than the original
		if isGreater(permutation, numbers) {
			if !foundNext {
				smallestCandidate = permutation
				foundNext = true
			} else {
				// Find the smallest permutation
				if isSmaller(permutation, smallestCandidate) {
					smallestCandidate = permutation
				}
			}
		}
	}

	// If no candidate found, return sorted
	if !foundNext {
		sort.Ints(numbers)
		copy(numbers, numbers)
		return
	}

	copy(numbers, smallestCandidate)
}

func generatePermutations(numbers []int) [][]int {
	var allPermutations [][]int
	var currentPermutation []int
	var used = make([]bool, len(numbers))

	var generate func()
	generate = func() {
		if len(currentPermutation) == len(numbers) {
			newPermutation := make([]int, len(numbers))
			copy(newPermutation, currentPermutation)
			allPermutations = append(allPermutations, newPermutation)
			return
		}

		for i := 0; i < len(numbers); i++ {
			if !used[i] {
				used[i] = true
				currentPermutation = append(currentPermutation, numbers[i])
				generate()
				used[i] = false
				currentPermutation = currentPermutation[:len(currentPermutation)-1]
			}
		}
	}

	generate()
	return allPermutations
}

func isGreater(first, second []int) bool {
	for i := 0; i < len(first); i++ {
		if first[i] > second[i] {
			return true
		} else if first[i] < second[i] {
			return false
		}
	}
	return false
}

func isSmaller(first, second []int) bool {
	for i := 0; i < len(first); i++ {
		if first[i] < second[i] {
			return true
		} else if first[i] > second[i] {
			return false
		}
	}
