use std::cmp::Ordering;

fn next_permutation_brute_force(numbers: &mut Vec<i32>) {
    let original_numbers = numbers.clone();
    let mut all_permutations: Vec<Vec<i32>> = Vec::new();
    generate_permutations(original_numbers.clone(), 0, &mut all_permutations);

    let mut next_greater_permutation: Option<Vec<i32>> = None;

    for permutation in all_permutations {
        match permutation.cmp(&original_numbers) {
            Ordering::Greater => {
                // Find the smallest permutation that is greater.
                match &next_greater_permutation {
                    Some(current_next) => {
                        if permutation < *current_next {
                            next_greater_permutation = Some(permutation);
                        }
                    }
                    None => {
                        next_greater_permutation = Some(permutation);
                    }
                }
            }
            _ => (),
        }
    }

    match next_greater_permutation {
        Some(permutation) => {
            numbers.clear();
            numbers.extend_from_slice(&permutation);
        }
        None => {
            // If there is no greater permutation, sort ascending
            numbers.sort();
        }
    }
}

fn generate_permutations(mut numbers: Vec<i32>, start_index: usize, all_permutations: &mut Vec<Vec<i32>>) {
    if start_index >= numbers.len() {
        all_permutations.push(numbers);
        return;
    }

    for index in start_index..numbers.len() {
        // Create all permutations by swapping each element
        numbers.swap(start_index, index);
        generate_permutations(numbers.clone(), start_index + 1, all_permutations);
    }
}

