fun generatePermutations(
    originalList: List<Int>, 
    currentPermutation: MutableList<Int>, 
    allPermutations: MutableList<IntArray>
) {
    if (originalList.isEmpty()) {
        allPermutations.add(currentPermutation.toIntArray())
        return
    }

    for (i in originalList.indices) {
        val number = originalList[i]
        val remainingNumbers = originalList.subList(0, i) + originalList.subList(i + 1, originalList.size)

        // Create a new permutation and recurse
        currentPermutation.add(number)
        generatePermutations(remainingNumbers, currentPermutation, allPermutations)

        // Backtrack to create all possible permutations
        currentPermutation.removeAt(currentPermutation.size - 1)
    }
}

