  for (let i = numbers.length - 2; i >= 0; i--) {
    if (numbers[i] < numbers[i + 1]) {
      indexOfDecrease = i;
      break;
    }
  }

  // If no decreasing element found, reverse the array
  if (indexOfDecrease === -1) {
    numbers.reverse();
    return numbers;
  }

  let indexOfSwap = -1;
  for (let i = numbers.length - 1; i > indexOfDecrease; i--) {
    if (numbers[i] > numbers[indexOfDecrease]) {
      indexOfSwap = i;
      break;
    }
  }

  // Swap the decreasing element and the element to swap with
  [numbers[indexOfDecrease], numbers[indexOfSwap]] = [numbers[indexOfSwap], numbers[indexOfDecrease]];

  // Reverse the portion of the array after the decreasing element
  let startOfReverse = indexOfDecrease + 1;
  let endOfReverse = numbers.length - 1;

  while (startOfReverse < endOfReverse) {
    [numbers[startOfReverse], numbers[endOfReverse]] = [numbers[endOfReverse], numbers[startOfReverse]];
    startOfReverse++;
    endOfReverse--;
  }

  return numbers;
}

