    numbers[indexOfNumberToSwap],
    numbers[indexOfDescreasingNumber],
  ];

  // Reverse the subarray after the decreasing number
  numbers.splice(
    indexOfDescreasingNumber + 1,
    numbers.length - (indexOfDescreasingNumber + 1),
    ...numbers
      .slice(indexOfDescreasingNumber + 1)
      .reverse()
  );
