public class Solution {
    public void nextPermutation(int[] nums) {
        int indexOfDescent = -1;
        for (int i = nums.length - 2; i >= 0; i--) {
            if (nums[i] < nums[i + 1]) {
                indexOfDescent = i;
                break;
            }
        }

        // If no such index exists, reverse the array
        if (indexOfDescent == -1) {
            reverseArray(nums, 0, nums.length - 1);
            return;
        }

        int indexOfSwap = -1;
        for (int i = nums.length - 1; i > indexOfDescent; i--) {
            if (nums[i] > nums[indexOfDescent]) {
                indexOfSwap = i;
                break;
            }
        }

        // Swap the values at the two indices.
        swap(nums, indexOfDescent, indexOfSwap);

        // Reverse the subarray starting from index + 1.
        reverseArray(nums, indexOfDescent + 1, nums.length - 1);
    }

    private void reverseArray(int[] nums, int start, int end) {
        while (start < end) {
            swap(nums, start, end);
            start++;
            end--;
        }
    }

    private void swap(int[] nums, int firstIndex, int secondIndex) {
        int temp = nums[firstIndex];
        nums[firstIndex] = nums[secondIndex];
        nums[secondIndex] = temp;
    }
}

