        for (int i = nums.size() - 2; i >= 0; i--) {
            if (nums[i] < nums[i + 1]) {
                indexOfDip = i;
                break;
            }
        }

        // If no dip, reverse the whole array
        if (indexOfDip == -1) {
            reverse(nums.begin(), nums.end());
            return;
        }

        // Find the smallest element to the right of dip
        int indexOfNextLarger = -1;
        for (int i = nums.size() - 1; i > indexOfDip; i--) {
            if (nums[i] > nums[indexOfDip]) {
                indexOfNextLarger = i;
                break;
            }
        }

        // Swap the dip with the next larger element
        swap(nums[indexOfDip], nums[indexOfNextLarger]);

        // Reverse the elements after the dip to find the smallest permutation
        reverse(nums.begin() + indexOfDip + 1, nums.end());
    }
