func nextPermutation(nums []int) {
	indexOfSmall := -1
	for i := len(nums) - 2; i >= 0; i-- {
		if nums[i] < nums[i+1] {
			indexOfSmall = i
			break
		}
	}

	if indexOfSmall == -1 {
		reverse(nums, 0, len(nums)-1)
		return
	}

	indexOfLarge := -1
	for i := len(nums) - 1; i > indexOfSmall; i-- {
		if nums[i] > nums[indexOfSmall] {
			indexOfLarge = i
			break
		}
	}

	// Swap to increase the number sequence
	nums[indexOfSmall], nums[indexOfLarge] = nums[indexOfLarge], nums[indexOfSmall]

	// Ensure no possibilities between sequences
	reverse(nums, indexOfSmall+1, len(nums)-1)
}

func reverse(nums []int, start int, end int) {
	for start < end {
		nums[start], nums[end] = nums[end], nums[start]
		start++
		end--
	}
}

