impl Solution {
    pub fn next_permutation(numbers: &mut Vec<i32>) {
        let numbers_length = numbers.len();

        // Find the first decreasing element from the right
        let mut first_decreasing_index: Option<usize> = None;
        for index in (0..(numbers_length - 1)).rev() {
            if numbers[index] < numbers[index + 1] {
                first_decreasing_index = Some(index);
                break;
            }
        }

        match first_decreasing_index {
            None => {
                // If no decreasing element, reverse the array
                numbers.reverse();
            }
            Some(decreasing_index) => {

                // Find the smallest element to the right of
                // decreasing_index that is greater than numbers[decreasing_index]
                let mut swap_index = decreasing_index + 1;
                for index in (decreasing_index + 1)..numbers_length {
                    if numbers[index] > numbers[decreasing_index] {
                        swap_index = index;
                    } else {
                        break;
                    }
                }

                // Find the index of the smallest element greater than numbers[decreasing_index]
                let mut smallest_greater_index = decreasing_index + 1;
                for index in (decreasing_index + 2..numbers_length).rev() {
                    if numbers[index] > numbers[decreasing_index] {
                        smallest_greater_index = index;
                        break;
                    }
                }

                //Swap these elements. This increases the number slightly.
                numbers.swap(decreasing_index, smallest_greater_index);

                // Reverse the elements to the right of decreasing_index
                // to get the smallest permutation of those elements
                let mut left = decreasing_index + 1;
                let mut right = numbers_length - 1;

                // The right side must be ascending for the next permutation
                while left < right {
                    numbers.swap(left, right);
                    left += 1;
                    right -= 1;
                }
            }
        }
    }
}

