fun nextPermutation(numbers: IntArray): Unit {
    val numbersLength = numbers.size
    var firstSmallNumberIndex = -1

    for (i in numbersLength - 2 downTo 0) {
      if (numbers[i] < numbers[i + 1]) {
        firstSmallNumberIndex = i
        break
      }
    }

    // If no such index exists, reverse the array.
    if (firstSmallNumberIndex == -1) {
      numbers.reverse()
      return
    }

    var smallestNumberGreaterThanFirst = -1

    // Find the smallest number to the right that is greater.
    for (i in numbersLength - 1 downTo 0) {
      if (numbers[i] > numbers[firstSmallNumberIndex]) {
        smallestNumberGreaterThanFirst = i
        break
      }
    }

    //Swap the numbers
    numbers[firstSmallNumberIndex] = numbers[smallestNumberGreaterThanFirst].also {
      numbers[smallestNumberGreaterThanFirst] = numbers[firstSmallNumberIndex]
    }

    // Reverse the sub-array after the first index.
    val start = firstSmallNumberIndex + 1
    var end = numbersLength - 1

    while (start < end) {
      numbers[start] = numbers[end].also {
        numbers[end] = numbers[start]
      }
      start++
      end--
    }
  }

