func nextPermutation(numbers: inout [Int]) {
    let arrayLength = numbers.count
    if arrayLength <= 1 { return }

    var indexToSwap = -1
    for i in (0...(arrayLength - 2)).reversed() {
        if numbers[i] < numbers[i + 1] {
            indexToSwap = i
            break
        }
    }

    // If no such index exists, reverse the array and return.
    if indexToSwap == -1 {
        numbers.reverse()
        return
    }

    var swapWithIndex = -1
    for i in (0...(arrayLength - 1)).reversed() {
        // Find the smallest number to the right of indexToSwap that is still larger.
        if numbers[i] > numbers[indexToSwap] {
            swapWithIndex = i
            break
        }
    }

    numbers.swapAt(indexToSwap, swapWithIndex)

    // Reverse the subarray starting from indexToSwap + 1.
    let start = indexToSwap + 1
    let end = arrayLength - 1
    var left = start
    var right = end

    // Reversing from indexToSwap to end ensures minimal increment.
    while left < right {
        numbers.swapAt(left, right)
        left += 1
        right -= 1
    }
}
